
(function(){
  const certs=[{"nombre":"Juan Angel Menchaca Tabares","fecha":"2025-06-19","certNombre":"angel menchaca 19 junio 2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Miguel Angel Sanchez Ponce","fecha":"2025-03-01","certNombre":"Angel sanchez ponce marzo 2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Carlos Vazquez Mondragón","fecha":"2025-06-01","certNombre":"Carlos vazquez mondragon junio 2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Arturo Lucas","fecha":"2025-06-18","certNombre":"certificado rational 18-19 junio arturo lucas 2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Eduardo Ruiz Perez","fecha":"2025-06-01","certNombre":"Eduardo ruiz junio 2025 (1).pdf","data":"data:application/pdf;base64,"},{"nombre":"Gabriel Balderas","fecha":"2025-04-01","certNombre":"Gabriel Balderas abril 2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Roberto Carlos Regalado Aguilera","fecha":"2025-03-01","certNombre":"ROBERTO REGALADO  MAR-2025.pdf","data":"data:application/pdf;base64,"},{"nombre":"Victor Hugo León León","fecha":"2025-09-01","certNombre":"victor hugo  leon  sep.2025.pdf","data":"data:application/pdf;base64,"}];
  // Ensure zone/year exists
  if(!YZD[CY][CZ]['2.1'])YZD[CY][CZ]['2.1']={};
  const zd=YZD[CY][CZ]['2.1'];
  if(!zd.m13cap)zd.m13cap={tecnicos:[]};
  const tecs=zd.m13cap.tecnicos;
  let added=0;
  certs.forEach(c=>{
    let tec=tecs.find(t=>t.nombre.toLowerCase().trim()===c.nombre.toLowerCase().trim());
    if(!tec){tec={nombre:c.nombre,sucursal:'',curso:'-4- Basic / Update training iCombi MEX',fechaCaducidad:'',certs:[]};tecs.push(tec);}
    if(!tec.certs)tec.certs=[];
    if(!tec.certs.find(x=>x.nombre===c.certNombre)){
      tec.certs.unshift({id:Date.now()+Math.random(),fecha:c.fecha,nombre:c.certNombre,data:c.data});
      added++;
    }
  });
  saveData();
  renderMain(CT);
  toast('✅ '+added+' certificados importados');
})();
